const express = require('express');
const bodyParser = require('body-parser');
const { exec } = require('child_process');
const { Configuration, OpenAIApi } = require('openai');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const dotenv = require('dotenv');

dotenv.config();

const app = express();
app.use(bodyParser.json());
app.use(helmet());

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
});
app.use(limiter);

const openai = new OpenAIApi(new Configuration({
  apiKey: process.env.OPENAI_API_KEY,
}));

const allowedCommands = ['node', 'python3']; // Allowlist for commands

function validateInput(input) {
  const regex = /^[a-zA-Z0-9\s.,;(){}[\]\"'`]+$/; // Basic validation
  return regex.test(input);
}

app.post('/generate-code', async (req, res) => {
  const { description } = req.body;

  if (!description || !validateInput(description)) {
    return res.status(400).json({ error: 'Invalid input' });
  }

  try {
    const response = await openai.createCompletion({
      model: 'text-davinci-003',
      prompt: description,
      max_tokens: 150,
    });

    const generatedCode = response.data.choices[0].text.trim();

    // Execute generated code securely
    const command = generatedCode.split(' ')[0];
    if (!allowedCommands.includes(command)) {
      return res.status(403).json({ error: 'Command not allowed' });
    }

    exec(generatedCode, (error, stdout, stderr) => {
      if (error) {
        return res.status(500).json({ error: stderr });
      }
      res.json({ output: stdout });
    });
  } catch (error) {
    res.status(500).json({ error: 'Error generating code' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});